import React, { useState } from "react";
import { useLocation } from "@reach/router";
import Header from "../../../componets/header/Header";
import Footer from "../../../componets/footer/Footer";
import { events } from "../../../data/events";
import { useLanguage } from "../../../context/LanguageContext";
import { getContent } from "../../../content/content";
import "../../../styles/checkout.css";

const CheckoutPage: React.FC = () => {
  const location = useLocation();
  const { lang } = useLanguage();
  const content = getContent(lang).pages.landing.section.eventContent;
  const eventSlug = location.pathname.split("/")[2];
  const eventData = events.find(e => e.id === eventSlug);
  const [selectedPlan, setSelectedPlan] = useState(eventData?.pricing[0]);

  if (!eventData) {
    return (
      <main style={{ background: '#1A202C', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Header />
        <div style={{ color: 'white', textAlign: 'center', padding: '2rem' }}>
          <h1 style={{ fontSize: '2rem', marginBottom: '1rem', color: '#D1A12A' }}>Event Not Found</h1>
          <p>The event you're looking for doesn't exist.</p>
        </div>
        <Footer />
      </main>
    );
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Mock payment processing
    setTimeout(() => {
      window.location.href = `/event/${eventSlug}/success`;
    }, 1000);
  };

  return (
    <>
      <Header />
      <main className="checkout-page">
        <div className="checkout-container">
          <div className="checkout-header">
            <h1 className="checkout-title">{content.checkout.title}</h1>
            <p className="checkout-subtitle">{eventData.name}</p>
          </div>

          <div className="checkout-content">
            <div className="checkout-form-section">
              <form className="checkout-form" onSubmit={handleSubmit}>
                <div className="form-group">
                  <label>{content.checkout.form.nameLabel}</label>
                  <input type="text" placeholder={content.checkout.form.namePlaceholder} required />
                </div>

                <div className="form-group">
                  <label>{content.checkout.form.emailLabel}</label>
                  <input type="email" placeholder={content.checkout.form.emailPlaceholder} required />
                </div>

                <div className="form-group">
                  <label>{content.checkout.form.phoneLabel}</label>
                  <input type="tel" placeholder={content.checkout.form.phonePlaceholder} required />
                </div>

                <div className="form-group">
                  <label>{content.checkout.form.companyLabel}</label>
                  <input type="text" placeholder={content.checkout.form.companyPlaceholder} />
                </div>

                <div className="form-group">
                  <label>{content.checkout.form.addressLabel}</label>
                  <input type="text" placeholder={content.checkout.form.addressPlaceholder} required />
                </div>

                <button type="submit" className="checkout-submit-btn">
                  {content.checkout.form.submitButton} - ${selectedPlan?.price || 0}
                </button>
              </form>
            </div>

            <div className="checkout-summary">
              <div className="summary-card">
                <h3>{content.checkout.summary.title}</h3>
                <div className="event-details">
                  <h4>{eventData.name}</h4>
                  <p>{new Date(eventData.date).toLocaleDateString()}</p>
                  <p>{eventData.location}</p>
                </div>
                
                <div className="plan-selection">
                  <h4>{content.checkout.summary.selectPlan}</h4>
                  {eventData.pricing.map((plan, index) => (
                    <div 
                      key={index} 
                      className={`plan-option ${selectedPlan?.name === plan.name ? 'selected' : ''}`}
                      onClick={() => setSelectedPlan(plan)}
                    >
                      <div className="plan-info">
                        <span className="plan-name">{plan.name}</span>
                        <span className="plan-price">${plan.price}</span>
                      </div>
                      <ul className="plan-features">
                        {plan.features.slice(0, 2).map((feature, i) => (
                          <li key={i}>{feature}</li>
                        ))}
                      </ul>
                    </div>
                  ))}
                </div>

                <div className="total">
                  <span>{content.checkout.summary.total}: ${selectedPlan?.price || 0}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>
      <Footer />
    </>
  );
};

export default CheckoutPage;